import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge: empty
  it("empty item list quote → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums for single items (no modifiers, customer with no history triggers first-insurance surcharge; use loyalty 0 / no special)
  // We'll use a customer with yearsWithMHPCO=0 and treat first item — but first insurance surcharge and 10% surcharge apply.
  // For purely "base premium" verification we need cases that exercise base only. Use integration-style descriptions.

  // Building block of 3 alike components — base premium only (these tests need a way to see just base premium; we instead use full quote with conditions that zero out other modifiers)
  // To verify base premium logic we use a long-standing customer scenario or just check the resulting premium reflects building block math.

  // Building block examples (use customer 0yrs, first quote, no curse, no enchant → only first-insurance 10% + 5G fee)
  it("quote 2 runes for new customer → premium = 50 base + 10% first insurance + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it.todo("quote 3 runes (block applies) → premium = 60 base + 10% first insurance + 5 fee = 71 G");
  it.todo("quote 4 runes (no block — block requires exactly 3) → premium = 100 base + 10% first insurance + 5 fee = 115 G");
  it.todo("quote 7 runes → premium = 175 base + 10% first insurance + 5 fee = 198 G (rounded up from 197.5)");

  // Alike components clarification
  it.todo("quote 2 runes + 1 moonstone → no block (different types), base 75 G → premium 88 G");
  it.todo("quote 3 runes + 3 moonstones → two separate blocks, base 120 G → premium 137 G");

  // Single item base premiums (verify each item type)
  it.todo("quote single sword (new customer) → 100 + 10 + 5 = 115 G");
  it.todo("quote single amulet (new customer) → 60 + 6 + 5 = 71 G");
  it.todo("quote single staff (new customer) → 80 + 8 + 5 = 93 G");
  it.todo("quote single potion (new customer) → 40 + 4 + 5 = 49 G");

  // Modifier thresholds
  it.todo("customer with exactly 2 years gets loyalty discount");
  it.todo("sword with enchantment exactly 5 gets high-enchantment surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("sword cursed and enchantment 5 → both surcharges apply");

  // Modifier scope on multi-item policies
  it.todo("policy of cursed sword + plain amulet → 100 + 60 base = 160, cursed adds 50 (50% of sword only) = 210 before fee/other modifiers");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) → premium 165 G");
  it.todo("long-standing customer's second contract (3 years, cursed sword enchantment 7, second quote) → premium 160 G");

  // First insurance applies per item regardless of follow-up
  it.todo("each item in a quote is first insurance regardless of customer history");

  // Rounding — premium
  it.todo("premium yielding 197.5 G is rounded up to 198 G (MHPCO's favor)");

  // Claim: standard reimbursement
  it.todo("regular sword damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune (no enchantment/material), damage 200 → payout 100");

  // High enchantment vs dragon material
  it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses; 50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon clause; full then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");

  // Multiple items of same type
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords (two entries) → each entry has its own deductible");
  it.todo("damages contains two sword entries but only one sword insured → CLI rejects with non-zero status");

  // Cap exhaustion
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword premium modifiers don't change cap → cap 2000 G");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount doesn't reduce insurance sum");
  it.todo("two successive 1500 claims on sword (cap 2000) → first payout 1400 (cap remaining 600), second 600 (cap 0)");

  // Rounding — payout
  it.todo("payout yielding 350.5 G is rounded down to 350 G (MHPCO's favor)");

  // Error edge cases
  it.todo("unknown item type in quote → CLI exits non-zero with stderr; no results on stdout");
  it.todo("claim damage references item not in policy → CLI exits non-zero with stderr");
  it.todo("claim damage with negative amount → CLI exits non-zero with stderr");
});

