type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const THREE_ALIKE_BLOCK_PREMIUM = 60;

type ItemTypeSpec = { basePremium: number; isComponent: boolean };

const ITEM_TYPES: Record<string, ItemTypeSpec> = {
  // Whole items
  sword: { basePremium: 100, isComponent: false },
  amulet: { basePremium: 60, isComponent: false },
  staff: { basePremium: 80, isComponent: false },
  potion: { basePremium: 40, isComponent: false },
  // Components (eligible for 3-alike block premium)
  rune: { basePremium: 25, isComponent: true },
  moonstone: { basePremium: 25, isComponent: true },
};

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const basePremiumForGroup = (type: string, count: number): number => {
  const spec = ITEM_TYPES[type];
  if (spec.isComponent && count === 3) return THREE_ALIKE_BLOCK_PREMIUM;
  return count * spec.basePremium;
};

const basePremiumFor = (items: Item[]): number =>
  [...countByType(items)]
    .reduce((sum, [type, count]) => sum + basePremiumForGroup(type, count), 0);

const applyFirstInsuranceSurcharge = (premium: number): number =>
  premium + (premium * FIRST_INSURANCE_SURCHARGE_PERCENT) / 100;

const quotePremium = (items: Item[]): number =>
  Math.ceil(applyFirstInsuranceSurcharge(basePremiumFor(items))) + PROCESSING_FEE;

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

