      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 148 }] });
  });
  it("sword with enchantment 4 has no high-enchantment surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("sword cursed and enchantment 5 → both surcharges apply", () => {
    // 100 base + 50 curse + 30 high-ench = 180; +10% first = 198; +5 = 203
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 203 }] });
  });

  // Modifier scope on multi-item policies
  it("policy of cursed sword + plain amulet → 100 + 60 base = 160, cursed adds 50 (50% of sword only) = 210 before fee/other modifiers", () => {
    // 160 base + 50 curse on sword only = 210; +10% first ins = 231; +5 = 236
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "sword", cursed: true },
          { type: "amulet" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 236 }] });
  });

  // Integration examples
  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) → premium 165 G");
  it.todo("long-standing customer's second contract (3 years, cursed sword enchantment 7, second quote) → premium 160 G");

  // First insurance applies per item regardless of follow-up
  it.todo("each item in a quote is first insurance regardless of customer history");

  // Rounding — premium
  it.todo("premium yielding 197.5 G is rounded up to 198 G (MHPCO's favor)");

  // Claim: standard reimbursement
  it.todo("regular sword damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune (no enchantment/material), damage 200 → payout 100");

  // High enchantment vs dragon material
  it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (both clauses; 50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (only dragon clause; full then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");

  // Multiple items of same type
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords (two entries) → each entry has its own deductible");
  it.todo("damages contains two sword entries but only one sword insured → CLI rejects with non-zero status");

  // Cap exhaustion
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword premium modifiers don't change cap → cap 2000 G");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G; block discount doesn't reduce insurance sum");
  it.todo("two successive 1500 claims on sword (cap 2000) → first payout 1400 (cap remaining 600), second 600 (cap 0)");

  // Rounding — payout
  it.todo("payout yielding 350.5 G is rounded down to 350 G (MHPCO's favor)");

  // Error edge cases
  it.todo("unknown item type in quote → CLI exits non-zero with stderr; no results on stdout");
  it.todo("claim damage references item not in policy → CLI exits non-zero with stderr");
  it.todo("claim damage with negative amount → CLI exits non-zero with stderr");
});

type Item = { type: string; enchantment?: number; cursed?: boolean; material?: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const THREE_ALIKE_BLOCK_PREMIUM = 60;

type ItemTypeSpec = { basePremium: number; isComponent: boolean };

const ITEM_TYPES: Record<string, ItemTypeSpec> = {
  // Whole items
  sword: { basePremium: 100, isComponent: false },
  amulet: { basePremium: 60, isComponent: false },
  staff: { basePremium: 80, isComponent: false },
  potion: { basePremium: 40, isComponent: false },
  // Components (eligible for 3-alike block premium)
  rune: { basePremium: 25, isComponent: true },
  moonstone: { basePremium: 25, isComponent: true },
};

const percentOf = (amount: number, percent: number): number => (amount * percent) / 100;

