type Item = { type: string; enchantment?: number; cursed?: boolean; material?: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
const THREE_ALIKE_BLOCK_PREMIUM = 60;

type ItemTypeSpec = { basePremium: number; isComponent: boolean };

const ITEM_TYPES: Record<string, ItemTypeSpec> = {
  // Whole items
  sword: { basePremium: 100, isComponent: false },
  amulet: { basePremium: 60, isComponent: false },
  staff: { basePremium: 80, isComponent: false },
  potion: { basePremium: 40, isComponent: false },
  // Components (eligible for 3-alike block premium)
  rune: { basePremium: 25, isComponent: true },
  moonstone: { basePremium: 25, isComponent: true },
};

const percentOf = (amount: number, percent: number): number => (amount * percent) / 100;

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const basePremiumForGroup = (type: string, count: number): number => {
  const spec = ITEM_TYPES[type];
  if (spec.isComponent && count === 3) return THREE_ALIKE_BLOCK_PREMIUM;
  return count * spec.basePremium;
};

const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const CURSE_SURCHARGE_PERCENT = 50;

// Each surcharge rule receives the item and its base premium and returns
// the surcharge amount in gold (0 when the rule does not apply).
type ItemSurchargeRule = (item: Item, itemBase: number) => number;

const ITEM_SURCHARGE_RULES: ItemSurchargeRule[] = [
  (item, itemBase) =>
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
      ? percentOf(itemBase, HIGH_ENCHANTMENT_SURCHARGE_PERCENT)
      : 0,
  (item, itemBase) =>
    item.cursed ? percentOf(itemBase, CURSE_SURCHARGE_PERCENT) : 0,
];

const itemSurcharges = (item: Item): number => {
  const itemBase = ITEM_TYPES[item.type].basePremium;
  return ITEM_SURCHARGE_RULES.reduce((sum, rule) => sum + rule(item, itemBase), 0);
};

const sumBy = <T>(items: T[], valueOf: (item: T) => number): number =>
  items.reduce((sum, item) => sum + valueOf(item), 0);

const itemsPremium = (items: Item[]): number => {
  const groupBaseTotal = sumBy(
    [...countByType(items)],
    ([type, count]) => basePremiumForGroup(type, count),
  );
  const surchargeTotal = sumBy(items, itemSurcharges);
  return groupBaseTotal + surchargeTotal;
};

const applyFirstInsuranceSurcharge = (premium: number): number =>
  premium + percentOf(premium, FIRST_INSURANCE_SURCHARGE_PERCENT);

const LOYALTY_DISCOUNT_PERCENT = 20;
const LOYALTY_MIN_YEARS = 2;

const applyLoyaltyDiscount = (premium: number, yearsWithMHPCO: number): number =>
  yearsWithMHPCO >= LOYALTY_MIN_YEARS ? premium - percentOf(premium, LOYALTY_DISCOUNT_PERCENT) : premium;

const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
  const afterLoyalty = applyLoyaltyDiscount(itemsPremium(items), yearsWithMHPCO);
  return Math.ceil(applyFirstInsuranceSurcharge(afterLoyalty)) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const years = scenario.customer.yearsWithMHPCO;
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items, years) }));
  return { results };
};

