const DEDUCTIBLE_PER_DAMAGE = 100;
const CAP_MULTIPLIER = 2;

const insuranceSum = (items: Item[]): number =>
  sumBy(items, (item) => ITEM_TYPES[item.type].insuranceValue);

type Policy = { items: Item[]; remainingCap: number };

const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
  const payout = sumBy(incident.damages, (damage) =>
    Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE),
  );
  policy.remainingCap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const yearsWithMHPCO = scenario.customer.yearsWithMHPCO;
  const policies: Policy[] = [];
  let priorQuoteCount = 0;
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const premium = quotePremium(step.items, { yearsWithMHPCO, priorQuoteCount });
      policies.push({ items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER });
      priorQuoteCount += 1;
      return { premium };
    }
    return processClaim(policies[step.policy], step.incident);
  });
  return { results };
};

